import{_ as e,o as a,c as i,a3 as r}from"./chunks/framework.LBeL10WQ.js";const p=JSON.parse('{"title":"Parcel Insert","description":"","frontmatter":{"title":"Parcel Insert"},"headers":[],"relativePath":"en/advertisers/sponsored-mail/index.md","filePath":"en/advertisers/sponsored-mail/index.md"}'),s={name:"en/advertisers/sponsored-mail/index.md"};function l(o,t,n,d,c,g){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="parcel-insert-sponsored-mail" tabindex="-1">Parcel Insert (Sponsored Mail) <a class="header-anchor" href="#parcel-insert-sponsored-mail" aria-label="Permalink to &quot;Parcel Insert (Sponsored Mail)&quot;">​</a></h1><p>Slip your offer (flyer, card, sample) inside the parcels of carefully selected e-retailers — and reach your customers at the moment of unboxing.</p><hr><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Select your distributors</h3><p>Browse the network of +250 partner e-retailers. Filter by sector, average basket, geography, and B2B/B2C profile to build your targeted media plan.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Create your materials</h3><p>Design your flyer respecting the <a href="./design-guide/print-specs">technical specifications</a> and the <a href="./design-guide/legal">legal notices</a>. Integrate the dynamic QR Code provided by getinside — it&#39;s your tracking tool.</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Warehouse delivery</h3><p>You ship your materials (or entrust printing to our Studio). getinside manages logistics and routing directly to the distributors&#39; warehouses.</p></div></div><div class="gi-step"><div class="gi-step-num done">4</div><div class="gi-step-body"><h3>Monitor in real-time</h3><p>Track QR scans and distributed volumes from your dashboard. Weekly reporting updated by each distributor.</p></div></div><hr><h2 id="why-this-channel-is-essential" tabindex="-1">Why this channel is essential <a class="header-anchor" href="#why-this-channel-is-essential" aria-label="Permalink to &quot;Why this channel is essential&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>📦 100% Open Rate</strong><p>The only physical media with an absolute pick-up rate. The customer eagerly awaits their parcel — your flyer is seen, held in hand, in a moment of maximum attention.</p></div><div class="gi-value-card"><strong>🎯 Behavioral Targeting</strong><p>You reach real buyers, qualified by their purchasing habits — not anonymous internet users. Sector, average basket, geography: targeting is precise and measurable.</p></div><div class="gi-value-card"><strong>🛡️ Cookie-less &amp; GDPR</strong><p>100% offline channel: no dependence on third-party cookies, no GDPR restrictions on targeting. A sustainable channel in the face of digital saturation and rising costs.</p></div></div><hr><h2 id="targeting-audiences" tabindex="-1">Targeting &amp; Audiences <a class="header-anchor" href="#targeting-audiences" aria-label="Permalink to &quot;Targeting &amp; Audiences&quot;">​</a></h2><p>Select your distributors based on four criteria:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Criterion</th><th style="text-align:left;">Available options</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Product universe</strong></td><td style="text-align:left;">Beauty, Food, Tech, Home, Sport, Fashion, Wellness...</td></tr><tr><td style="text-align:left;"><strong>Average Order Value (AOV)</strong></td><td style="text-align:left;">High-end, Mass Market, Discounter, Budget</td></tr><tr><td style="text-align:left;"><strong>Buyer profile</strong></td><td style="text-align:left;">B2C (individuals) or B2B (professionals)</td></tr><tr><td style="text-align:left;"><strong>Geography</strong></td><td style="text-align:left;">France, Belgium, Spain, Germany...</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Guaranteed sector exclusivity</p><p>Your offer is always inserted with a <strong>non-competing</strong> e-retailer. And in the same parcel, two competing offers can never coexist.</p></div><hr><h2 id="formats" tabindex="-1">Formats <a class="header-anchor" href="#formats" aria-label="Permalink to &quot;Formats&quot;">​</a></h2><h3 id="flyers-cards" tabindex="-1">Flyers &amp; Cards <a class="header-anchor" href="#flyers-cards" aria-label="Permalink to &quot;Flyers &amp; Cards&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Finished dimensions</th><th style="text-align:left;">Recommended use</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>A5</strong></td><td style="text-align:left;">148 × 210 mm</td><td style="text-align:left;">Standard format — ideal for detailed offers</td></tr><tr><td style="text-align:left;"><strong>A6</strong></td><td style="text-align:left;">105 × 148 mm</td><td style="text-align:left;">Compact format — ideal for promo codes</td></tr><tr><td style="text-align:left;"><strong>Card</strong></td><td style="text-align:left;">105 × 148 mm</td><td style="text-align:left;">Gift or loyalty card format</td></tr></tbody></table><h3 id="samples-sampling" tabindex="-1">Samples (Sampling) <a class="header-anchor" href="#samples-sampling" aria-label="Permalink to &quot;Samples (Sampling)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Format</th><th style="text-align:left;">Max weight</th><th style="text-align:left;">Max developed</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>S</strong></td><td style="text-align:left;">15 g</td><td style="text-align:left;">15 cm</td></tr><tr><td style="text-align:left;"><strong>M</strong></td><td style="text-align:left;">100 g</td><td style="text-align:left;">30 cm</td></tr><tr><td style="text-align:left;"><strong>L</strong></td><td style="text-align:left;">450 g</td><td style="text-align:left;">40 cm</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Duo Option — Flyer + Sample</p><p>An S Format sample can be attached to an A5/A6 flyer via a dot of fugitive (repositionable) glue. Produced by Adapted Enterprises (EA).</p></div><hr><h2 id="performance-roi" tabindex="-1">Performance &amp; ROI <a class="header-anchor" href="#performance-roi" aria-label="Permalink to &quot;Performance &amp; ROI&quot;">​</a></h2><p>Benchmarks observed on the getinside network:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Indicator</th><th style="text-align:left;">Network benchmark</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Scan rate (CTR)</strong></td><td style="text-align:left;">1% to 10%</td></tr><tr><td style="text-align:left;"><strong>Post-scan conversion rate (CVR)</strong></td><td style="text-align:left;">10% to 30%</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Maximize ROI</p><ul><li><strong>Monetary value</strong>: <em>&quot;10€ off&quot;</em> converts much better than <em>&quot;-10%&quot;</em>. Concrete value is immediately perceived.</li><li><strong>QR Code + UTM</strong>: combine the getinside QR code with UTM parameters (<code>utm_source=getinside&amp;utm_medium=parcel-insert</code>) to track sales in Google Analytics.</li><li><strong>Unique promo code</strong>: add a specific code per distributor for offline attribution.</li><li><strong>Validity period</strong>: allow at least 3 months — recipients often keep flyers for several weeks before scanning them.</li></ul></div><hr><h2 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Item</th><th style="text-align:left;">Cost</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Platform access</strong></td><td style="text-align:left;">Free, no subscription</td></tr><tr><td style="text-align:left;"><strong>Platform fee</strong></td><td style="text-align:left;">12% of invested media budget</td></tr><tr><td style="text-align:left;"><strong>Printing</strong> (optional)</td><td style="text-align:left;">Sliding scale rates for group purchases — Made in France, Imprim&#39;Vert certified</td></tr><tr><td style="text-align:left;"><strong>Creative Studio</strong> (optional)</td><td style="text-align:left;">Flat fee 550€ HT per campaign</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">No minimum commitment</p><p>You launch your first campaign whenever you want, with the budget you choose. Platform fees only apply to the actually committed budget.</p></div><hr><h2 id="why-go-through-getinside" tabindex="-1">Why go through getinside? <a class="header-anchor" href="#why-go-through-getinside" aria-label="Permalink to &quot;Why go through getinside?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🌐 Exclusive Network</strong><p>+250 partner e-retailers with niche audiences often inaccessible directly. A single point of contact for the entire network.</p></div><div class="gi-value-card"><strong>🏭 Integrated Logistics</strong><p>Made in France printing (Imprim&#39;Vert, FSC), packaging, and warehouse delivery managed by getinside. You focus on your campaign.</p></div><div class="gi-value-card"><strong>📊 Centralized Management</strong><p>A single dashboard to track distributions (weekly reporting) and QR performance (real-time scans). Zero coordination emails.</p></div></div><hr><h2 id="get-started" tabindex="-1">Get started <a class="header-anchor" href="#get-started" aria-label="Permalink to &quot;Get started&quot;">​</a></h2><p><strong>Ready to launch your first campaign?</strong></p><ul><li><a href="./design-guide/">📘 Design Guide</a> — Technical specifications, legal notices, creative strategy.</li><li><a href="https://app.getinside.media/" target="_blank">🚀 Create a campaign</a> — Access the platform directly.</li></ul><div class="info custom-block"><p class="custom-block-title">Need help?</p><p>Our Creative Studio handles art direction and execution for <strong>550€ HT</strong> per campaign. → <a href="./../../resources/studio.html">Contact the Studio</a></p></div>',40)])])}const u=e(s,[["render",l]]);export{p as __pageData,u as default};
